SELECT ROUND(100.0 * COUNT(*) FILTER (WHERE "FishingReason_Enjoyment")
                   / NULLIF(COUNT("FishingReason_Enjoyment"), 0), 1) AS pct_enjoyment
FROM "C01_AASurvey_exemplarydata";

SELECT ROUND(100.0 * COUNT(*) FILTER (WHERE "FishingReason_Competition")
                   / NULLIF(COUNT("FishingReason_Competition"), 0), 1) AS pct_competition
FROM "C01_AASurvey_exemplarydata";

SELECT ROUND(100.0 * COUNT(*) FILTER (WHERE "UseAA_Maps")
                   / NULLIF(COUNT("UseAA_Maps"), 0), 1) AS pct_useaa_maps
FROM "C01_AASurvey_exemplarydata";

SELECT ROUND(100.0 * COUNT(*) FILTER (WHERE "Status" = 1)
                   / NULLIF(COUNT("Status"), 0), 1) AS pct_married
FROM "C01_AASurvey_exemplarydata";

SELECT ROUND(100.0 * COUNT(*) FILTER (WHERE "Vehicle" = 0)
                   / NULLIF(COUNT("Vehicle"), 0), 1) AS pct_vehicle_always
FROM "C01_AASurvey_exemplarydata";

SELECT ROUND(100.0 * COUNT(*) FILTER (WHERE "ImpactDistance")
             / NULLIF(COUNT("ImpactDistance"), 0), 1) AS pct_distance_matters
FROM "C01_AASurvey_exemplarydata";

SELECT count("DF") AS n_mammals_with_pitch
FROM "Data"
WHERE "Class" = 'Mammalia';

SELECT count("DF") AS n_frogs_with_pitch
FROM "Data"
WHERE "Class" = 'Amphibia';

SELECT min("DF") AS min_dominant_freq_hz,
       max("DF") AS max_dominant_freq_hz
FROM "Data";

SELECT count(*) FILTER (WHERE "BM" <= 0) AS nonpositive_body_mass,
       count(*) FILTER (WHERE "DF" <= 0) AS nonpositive_dominant_freq
FROM "Data";

WITH m AS (SELECT DISTINCT "mother.id", "mother.length" FROM "diversityDat" WHERE "mother.length" IS NOT NULL)
SELECT count(*) AS n_mothers, round(avg("mother.length")::numeric, 2) AS mean_mm,
       round(min("mother.length")::numeric, 1) AS min_mm, round(max("mother.length")::numeric, 1) AS max_mm FROM m;

SELECT 'Offspring_number' AS table_name, count(*) AS n_rows FROM "Offspring_number"
UNION ALL SELECT 'diversityDat', count(*) FROM "diversityDat"
UNION ALL SELECT 'PaternityFile', count(*) FROM "PaternityFile";

WITH pm AS (SELECT DISTINCT "mother.id", "prob.lay" FROM "Offspring_number" WHERE "year" = 2019)
SELECT count(*) AS n_females, sum("prob.lay") AS n_laid,
       round(avg("prob.lay")::numeric, 3) AS fraction_laid FROM pm;

SELECT "father.mate" AS n_mates, count(DISTINCT "mother.id") AS n_mothers
FROM "Offspring_number" WHERE "year" = 2018
GROUP BY "father.mate" ORDER BY "father.mate";

SELECT count(*) FILTER (WHERE "father.mate" = 1 AND "treatment" <> '1x') AS one_mate_not_1x,
       count(*) FILTER (WHERE "father.mate" > 1 AND "treatment" <> 'Mx') AS many_mates_not_mx
FROM "Offspring_number" WHERE "father.mate" IS NOT NULL;

SELECT COUNT(*) FILTER (
  WHERE "number_doses_before_covid" NOT IN (
    'pre-dose 1','Dose 2','Dose 3','Dose 4','Dose 5','Dose 6','NA'
  )
) AS invalid_categories
FROM "new_elisa_public"
WHERE "number_doses_before_covid" IS NOT NULL;

SELECT MIN("day_mean_temp_ib") AS min_temp, MAX("day_mean_temp_ib") AS max_temp,
       COUNT(*) FILTER (WHERE "day_mean_temp_ib" < 0) AS n_subzero
FROM "TreeHoles_Ibuttons_Infection_Ecol";

SELECT COUNT("Symb.pHi") AS symb_phi, COUNT("Nonsymb.pHi") AS nonsymb_phi,
              COUNT("Tissue.Integrity") AS histology, COUNT("Gametes") AS gametes
       FROM "ApocHeatStress";

SELECT COUNT(*) AS rows, COUNT(DISTINCT ("Colony","Treatment")) AS ramets,
              COUNT(*) FILTER (WHERE NULLIF(NULLIF(trim("Change per day (g/cm2/d)"),'N/A'),'') IS NOT NULL) AS numeric_values
       FROM "ApocRawBuoyantWeights";

SELECT COUNT(DISTINCT "Virus") AS n_detected_viruses
FROM read_coverage
WHERE perc_coverage > 0.33 AND "perc_RdRp_coverage" > 0.75;

SELECT COUNT(*) AS bumblebee_libraries_with_both_dwv
FROM virus_wide_summary
WHERE "Species" = 'B. terrestris' AND "DWV-A" > 0 AND "DWV-B" > 0;

SELECT COUNT(*) AS honeybee_libraries_with_both_bqcv_variants
FROM virus_wide_summary
WHERE "Species" = 'A. mellifera' AND "BQCV Cherb." > 0 AND "BQCV B-I" > 0;

SELECT COUNT(*) FILTER (WHERE perc_coverage < 0 OR perc_coverage > 1) AS bad_perc_coverage,
       COUNT(*) FILTER (WHERE "perc_RdRp_coverage" < 0 OR "perc_RdRp_coverage" > 1) AS bad_rdrp_coverage
FROM read_coverage;

SELECT count(*) FILTER (WHERE "Other_causes" IS NOT NULL AND lower(trim("Other_causes")) NOT IN ('na','n/a','none','')) AS studies_with_alt_causes,
       count(*) AS total_studies
FROM review_mosquito_data;
